#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int sum = 0;
        for (int i = 1; i * i <= N; i++) {
            if (N % i == 0) {
                sum += i;
                if (i * i != N) sum += N / i;
            }
        }
        printf("%d\n", sum);
    }
    return 0;
}

