import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int sum = 0;
            for (int i = 1; i * i <= N; i++) {
                if (N % i == 0) {
                    sum += i;
                    if (i * i != N) sum += N / i;
                }
            }
            System.out.println(sum);
        }
    }
}

